def weather_advice(temperature):
    if temperature > 30:
        return "It's hot! Drink lots of water. 🔥"
    elif temperature > 15:
        return "Nice day for a walk! 😀"
    else:
        return "Grab a jacket, it's chilly! 🧥"

print(weather_advice(35))
print(weather_advice(20))
print(weather_advice(5))
